const item = $input.first().json;
const gargalos = typeof item.gargalos === 'string' ? JSON.parse(item.gargalos) : (item.gargalos || []);
const gargalosTexto = Array.isArray(gargalos) ? gargalos.join('\n- ') : JSON.stringify(gargalos);

const prompt = `Você é um especialista em análise de falhas operacionais. Analise os gargalos identificados no processo abaixo e classifique cada falha.

Processo: ${item.processo_nome}
Área: ${item.area}
Criticidade do processo: ${item.criticidade}

Gargalos identificados:
- ${gargalosTexto}

Para cada gargalo, retorne um JSON array com objetos no seguinte formato:
[
  {
    "tipo_falha": "categoria da falha (ex: gargalo_fluxo, falha_comunicacao, recurso_insuficiente, processo_incompleto, tecnologia_inadequada)",
    "descricao": "descrição detalhada da falha",
    "frequencia": 1,
    "condicoes": {"contexto": "quando ocorre", "triggers": []},
    "impacto_estimado": "impacto estimado em termos de produtividade ou custo",
    "status": "ativo"
  }
]

Retorne APENAS o JSON array válido, sem markdown.`;

return [{
  json: {
    ...item,
    prompt
  }
}];

const response = $input.first().json;
const content = response.content?.[0]?.text || '[]';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = {erro: 'parse_failed', raw: content}; }

// Se parsed não é array, encapsula
const falhas = Array.isArray(parsed) ? parsed : (parsed.erro ? [] : [parsed]);

// Retorna um item por falha detectada para processar individualmente
if (falhas.length === 0) {
  return [{json: {...$input.first().json, resultado: null, skip: true}}];
}

return falhas.map(falha => ({
  json: {
    ...$input.first().json,
    resultado: falha,
    skip: false
  }
}));
